import{_ as e,o as a,c as o,ag as d}from"./chunks/framework.5wcOFaQl.js";const g=JSON.parse('{"title":"ComfyUI Guide 🎨","description":"","frontmatter":{},"headers":[],"relativePath":"comfyui-guide.md","filePath":"comfyui-guide.md"}'),n={name:"comfyui-guide.md"};function r(i,t,s,l,h,c){return a(),o("div",null,[...t[0]||(t[0]=[d(`<h1 id="comfyui-guide-🎨" tabindex="-1">ComfyUI Guide 🎨 <a class="header-anchor" href="#comfyui-guide-🎨" aria-label="Permalink to &quot;ComfyUI Guide 🎨&quot;">​</a></h1><blockquote><p><strong>ComfyUI</strong> ist eine visuelle Node-basierte Workflow-Engine für generative KI.<br> Alles läuft <strong>lokal</strong> auf deiner GPU — Bilder, Videos und Audio.<br> Server: <strong><a href="http://127.0.0.1:8188" target="_blank" rel="noreferrer">http://127.0.0.1:8188</a></strong></p></blockquote><hr><h2 id="📷-bilder-erstellen-text→bild" tabindex="-1">📷 Bilder erstellen (Text→Bild) <a class="header-anchor" href="#📷-bilder-erstellen-text→bild" aria-label="Permalink to &quot;📷 Bilder erstellen (Text→Bild)&quot;">​</a></h2><h3 id="standard-workflow-txt2img" tabindex="-1">Standard Workflow (txt2img) <a class="header-anchor" href="#standard-workflow-txt2img" aria-label="Permalink to &quot;Standard Workflow (txt2img)&quot;">​</a></h3><p>Ein einfacher SDXL-Workflow besteht aus diesen Nodes:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LoadCheckpoint → CLIPTextEncode (positiv) → KSampler → VAEDecode → SaveImage</span></span>
<span class="line"><span>              → CLIPTextEncode (negativ)  ↗</span></span>
<span class="line"><span>              → EmptyLatentImage         ↗</span></span></code></pre></div><h3 id="schritt-fur-schritt-im-gui" tabindex="-1">Schritt-für-Schritt im GUI <a class="header-anchor" href="#schritt-fur-schritt-im-gui" aria-label="Permalink to &quot;Schritt-für-Schritt im GUI&quot;">​</a></h3><ol><li><strong>ComfyUI öffnen</strong> → <a href="http://127.0.0.1:8188" target="_blank" rel="noreferrer">http://127.0.0.1:8188</a></li><li>Per <strong>Rechtsklick → &quot;Add Node&quot;</strong> die Nodes hinzufügen: <ul><li><code>Add Node → loaders → Load Checkpoint</code> → SDXL auswählen</li><li><code>Add Node → conditioning → CLIP Text Encode (Prompt)</code> → dein Prompt</li><li>Nochmal <code>CLIP Text Encode</code> für Negative Prompts</li><li><code>Add Node → latent → Empty Latent Image</code> → Größe (1024x1024 für SDXL)</li><li><code>Add Node → sampling → KSampler</code> → 25 Steps, cfg 7, euler</li><li><code>Add Node → image → VAE Decode</code></li><li><code>Add Node → image → Save Image</code></li></ul></li><li><strong>Verbinden</strong> — Kabel von Node zu Node ziehen</li><li><strong>Prompt eingeben</strong> — im CLIPTextEncode-Node</li><li><strong>Queue Prompt</strong> klicken (rechts oben) → GPU rechnet</li><li>Bild erscheint im <strong>Save Image</strong>-Node</li></ol><h3 id="prompt-tipps" tabindex="-1">Prompt-Tipps <a class="header-anchor" href="#prompt-tipps" aria-label="Permalink to &quot;Prompt-Tipps&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Element</th><th>Beispiel</th></tr></thead><tbody><tr><td><strong>Stil</strong></td><td>photorealistic, cinematic, oil painting, anime, sketch</td></tr><tr><td><strong>Licht</strong></td><td>golden hour, dramatic lighting, soft diffused light</td></tr><tr><td><strong>Details</strong></td><td>8k, highly detailed, intricate, sharp focus</td></tr><tr><td><strong>Negativ</strong></td><td>blurry, low quality, distorted, watermark, text</td></tr></tbody></table><h3 id="wichtige-parameter" tabindex="-1">Wichtige Parameter <a class="header-anchor" href="#wichtige-parameter" aria-label="Permalink to &quot;Wichtige Parameter&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th style="text-align:center;">Wert</th><th>Effekt</th></tr></thead><tbody><tr><td><strong>Steps</strong></td><td style="text-align:center;">20–30</td><td>Mehr = feinere Details (aber langsamer)</td></tr><tr><td><strong>CFG</strong></td><td style="text-align:center;">7–10</td><td>Höher = prompttreuer (aber Overkill ab 15)</td></tr><tr><td><strong>Seed</strong></td><td style="text-align:center;">beliebig</td><td>Gleicher Seed = gleiches Bild</td></tr><tr><td><strong>Size</strong></td><td style="text-align:center;">1024×1024</td><td>SDXL-Optimalgröße</td></tr><tr><td><strong>Sampler</strong></td><td style="text-align:center;">euler / dpmpp_2m</td><td>euler = schnell, dpmpp = qualitativ</td></tr></tbody></table><blockquote><p>⚠️ <strong>SDXL</strong> läuft optimal auf <strong>1024×1024</strong>. Andere Größen können zu verzerrten Ergebnissen führen. Für Hoch-/Querformat: 896×1152 oder 1216×832.</p></blockquote><hr><h2 id="🎵-audio-erstellen" tabindex="-1">🎵 Audio erstellen <a class="header-anchor" href="#🎵-audio-erstellen" aria-label="Permalink to &quot;🎵 Audio erstellen&quot;">​</a></h2><p>ComfyUI unterstützt Audiogenerierung durch <strong>MusicGen / AudioCraft</strong> oder ähnliche Audio-Workflows.</p><h3 id="nodes-fur-audio" tabindex="-1">Nodes für Audio <a class="header-anchor" href="#nodes-fur-audio" aria-label="Permalink to &quot;Nodes für Audio&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LoadCheckpoint (Audio-Modell) → TextEncoder → AudioDecoder → SaveAudio</span></span></code></pre></div><h3 id="voraussetzung" tabindex="-1">Voraussetzung <a class="header-anchor" href="#voraussetzung" aria-label="Permalink to &quot;Voraussetzung&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># MusicGen-Nodes installieren</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">comfy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> comfyui-musicgen</span></span></code></pre></div><h3 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><ol><li><strong>Node:</strong> <code>Load Checkpoint</code> → ein Audio-Modell laden (z.B. MusicGen)</li><li><strong>Node:</strong> <code>Text Encoder</code> → Prompt eingeben (z.B. &quot;melodic synthwave, 90bpm&quot;)</li><li><strong>Node:</strong> <code>Audio Decode</code> → Parameter: Dauer in Sekunden</li><li><strong>Node:</strong> <code>Save Audio</code> → Ausgabe als WAV/MP3</li></ol><h3 id="audio-prompt-beispiele" tabindex="-1">Audio-Prompt-Beispiele <a class="header-anchor" href="#audio-prompt-beispiele" aria-label="Permalink to &quot;Audio-Prompt-Beispiele&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Stil</th><th>Prompt</th></tr></thead><tbody><tr><td><strong>Synthwave</strong></td><td>&quot;retro synthwave, driving bassline, 80s vibe, 120bpm&quot;</td></tr><tr><td><strong>Klassik</strong></td><td>&quot;string quartet, melancholic melody, classical&quot;</td></tr><tr><td><strong>Ambient</strong></td><td>&quot;deep ambient soundscape, ethereal pads, slow&quot;</td></tr><tr><td><strong>Lo-Fi</strong></td><td>&quot;lofi hip hop, relaxed beat, vinyl crackle, jazz sample&quot;</td></tr></tbody></table><blockquote><p>ℹ️ <strong>Hinweis:</strong> Audio-Workflows brauchen viel VRAM (≥12 GB empfohlen).<br> Deine RX 9060 XT (16 GB) ist gut geeignet.</p></blockquote><hr><h2 id="🎬-video-erstellen" tabindex="-1">🎬 Video erstellen <a class="header-anchor" href="#🎬-video-erstellen" aria-label="Permalink to &quot;🎬 Video erstellen&quot;">​</a></h2><h3 id="option-1-animatediff-bewegung-aus-standbildern" tabindex="-1">Option 1: AnimateDiff (Bewegung aus Standbildern) <a class="header-anchor" href="#option-1-animatediff-bewegung-aus-standbildern" aria-label="Permalink to &quot;Option 1: AnimateDiff (Bewegung aus Standbildern)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># AnimateDiff-Node installieren</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">comfy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> comfyui-animatediff-evolved</span></span></code></pre></div><p><strong>Workflow:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LoadCheckpoint → CLIPTextEncode → KSampler → AnimateDiffLoader</span></span>
<span class="line"><span>                                      ↓</span></span>
<span class="line"><span>                              LatentKeyframeGroup</span></span>
<span class="line"><span>                                      ↓</span></span>
<span class="line"><span>                              AnimateDiffSampler</span></span>
<span class="line"><span>                                      ↓</span></span>
<span class="line"><span>                              VAEDecode → SaveVideo (GIF/MP4)</span></span></code></pre></div><h3 id="option-2-hunyuan-video-ki-video-aus-text" tabindex="-1">Option 2: Hunyuan Video (KI-Video aus Text) <a class="header-anchor" href="#option-2-hunyuan-video-ki-video-aus-text" aria-label="Permalink to &quot;Option 2: Hunyuan Video (KI-Video aus Text)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">comfy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> comfyui-hunyuan-video</span></span></code></pre></div><p><strong>Workflow:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LoadHunyuanVideo → TextEncode → KSampler → VAEDecode → SaveVideo</span></span></code></pre></div><h3 id="parameter-fur-video" tabindex="-1">Parameter für Video <a class="header-anchor" href="#parameter-fur-video" aria-label="Permalink to &quot;Parameter für Video&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th style="text-align:center;">AnimateDiff</th><th style="text-align:center;">Hunyuan</th></tr></thead><tbody><tr><td><strong>Frames</strong></td><td style="text-align:center;">16–32</td><td style="text-align:center;">49–129</td></tr><tr><td><strong>Auflösung</strong></td><td style="text-align:center;">512×512</td><td style="text-align:center;">640×480</td></tr><tr><td><strong>Steps</strong></td><td style="text-align:center;">20–25</td><td style="text-align:center;">25–50</td></tr><tr><td><strong>VRAM</strong></td><td style="text-align:center;">~8 GB</td><td style="text-align:center;">~14 GB</td></tr><tr><td><strong>Dauer</strong></td><td style="text-align:center;">1–3 Min</td><td style="text-align:center;">5–20 Min</td></tr></tbody></table><blockquote><p>⚠️ <strong>Video ist VRAM-intensiv!</strong> AnimateDiff läuft gut auf 16 GB.<br> Hunyuan Video ist grenzwertig — wenn&#39;s crasht, Cloud nutzen.</p></blockquote><hr><h2 id="📂-wichtige-ordner" tabindex="-1">📂 Wichtige Ordner <a class="header-anchor" href="#📂-wichtige-ordner" aria-label="Permalink to &quot;📂 Wichtige Ordner&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Pfad</th><th style="text-align:left;">Inhalt</th></tr></thead><tbody><tr><td style="text-align:left;"><code>~/comfy/ComfyUI/models/checkpoints/</code></td><td style="text-align:left;">Deine Modelle (SDXL, Flux, etc.)</td></tr><tr><td style="text-align:left;"><code>~/comfy/ComfyUI/models/loras/</code></td><td style="text-align:left;">LoRA-Adapter</td></tr><tr><td style="text-align:left;"><code>~/comfy/ComfyUI/models/vae/</code></td><td style="text-align:left;">VAE-Dateien</td></tr><tr><td style="text-align:left;"><code>~/comfy/ComfyUI/output/</code></td><td style="text-align:left;">Generierte Bilder/Videos/Audio</td></tr><tr><td style="text-align:left;"><code>~/comfy/ComfyUI/custom_nodes/</code></td><td style="text-align:left;">Installierte Custom Nodes</td></tr><tr><td style="text-align:left;"><code>/tmp/comfyui.log</code></td><td style="text-align:left;">Server-Log</td></tr></tbody></table><hr><h2 id="💾-workflows-speichern-laden" tabindex="-1">💾 Workflows speichern &amp; laden <a class="header-anchor" href="#💾-workflows-speichern-laden" aria-label="Permalink to &quot;💾 Workflows speichern &amp; laden&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aktion</th><th>Tastenkürzel / Menü</th></tr></thead><tbody><tr><td><strong>Workflow speichern</strong></td><td><code>Strg + S</code> → als <code>.json</code> speichern</td></tr><tr><td><strong>Workflow laden</strong></td><td><code>Strg + O</code> → <code>.json</code> laden</td></tr><tr><td><strong>Als API-Format exportieren</strong></td><td>Menü → &quot;Save (API Format)&quot;</td></tr><tr><td><strong>Default-Workflow laden</strong></td><td>Menü → &quot;Load Default&quot;</td></tr><tr><td><strong>Clear (alles löschen)</strong></td><td>Rechtsklick → &quot;Clear&quot;</td></tr></tbody></table><hr><h2 id="🛠️-nutzliche-tastenkurzel" tabindex="-1">🛠️ Nützliche Tastenkürzel <a class="header-anchor" href="#🛠️-nutzliche-tastenkurzel" aria-label="Permalink to &quot;🛠️ Nützliche Tastenkürzel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kürzel</th><th>Funktion</th></tr></thead><tbody><tr><td><code>Strg + S</code></td><td>Workflow speichern</td></tr><tr><td><code>Strg + O</code></td><td>Workflow laden</td></tr><tr><td><code>Strg + Z</code></td><td>Rückgängig</td></tr><tr><td><code>Strg + A</code></td><td>Alle Nodes markieren</td></tr><tr><td><code>Entf</code></td><td>Ausgewählte Nodes löschen</td></tr><tr><td><code>Strg + Enter</code></td><td>Queue Prompt (Generation starten)</td></tr><tr><td><code>Mittlere Maustaste</code></td><td>Canvas verschieben</td></tr><tr><td><code>Mausrad</code></td><td>Zoom</td></tr><tr><td><code>Doppelklick</code></td><td>Node-Suche öffnen</td></tr></tbody></table><hr><h2 id="❌-fehlerbehebung" tabindex="-1">❌ Fehlerbehebung <a class="header-anchor" href="#❌-fehlerbehebung" aria-label="Permalink to &quot;❌ Fehlerbehebung&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Lösung</th></tr></thead><tbody><tr><td><strong>&quot;CUDA out of memory&quot;</strong></td><td>Steps reduzieren, geringere Auflösung, <code>--lowvram</code> Flag</td></tr><tr><td><strong>&quot;Module not found&quot;</strong></td><td>Fehlende Custom Nodes installieren: <code>comfy node install &lt;name&gt;</code></td></tr><tr><td><strong>&quot;Checkpoint not found&quot;</strong></td><td>Modell fehlt — <code>comfy model download --url ...</code></td></tr><tr><td><strong>Server startet nicht</strong></td><td><code>/tmp/comfyui.log</code> prüfen, <code>.venv</code> evtl. neu mit <code>comfy install --restore --amd</code></td></tr><tr><td><strong>Bild wird schwarz</strong></td><td>Falscher VAE oder Modell nicht geladen — Checkpoint prüfen</td></tr></tbody></table>`,51)])])}const u=e(n,[["render",r]]);export{g as __pageData,u as default};
